import React from 'react';
import './Experience.css';

const Experience = () => {
  const experiences = [
    {
      company: "MH Talent Craft Solutions",
      role: "UI/UX Designer Intern",
      type: "Remote",
      period: "Oct 2025 – Jan 2026",
      description: "Worked on UX research, user flows, wireframes, and interactive prototypes for web interfaces.",
      icon: "💼"
    },
    {
      company: "Zidio",
      role: "UI/UX Designer Intern",
      type: "Remote",
      period: "Apr 2025 – Jul 2025",
      description: "Designed mobile and web UI screens, wireframes, and user flows using Figma.",
      icon: "🎨"
    },
    {
      company: "Uxdose",
      role: "UI/UX & Graphic Design Intern",
      type: "Remote",
      period: "May 2025 – Jul 2025",
      description: "Created UI layouts and digital graphics while maintaining brand consistency and iterating based on feedback.",
      icon: "✏️"
    }
  ];

  return (
    <section className="experience" id="experience">
      <div className="experience-container">
        <div className="section-header">
          <h2 className="section-title">Internship Experience</h2>
          <div className="title-underline"></div>
        </div>

        <div className="experience-content">
          {experiences.map((exp, index) => (
            <div key={index} className="experience-card">
              <div className="card-glow"></div>
              <div className="experience-header">
                <div className="company-icon">{exp.icon}</div>
                <div className="experience-info">
                  <h3 className="company-name">{exp.company}</h3>
                  <p className="role-title">{exp.role}</p>
                  <div className="experience-meta">
                    <span className="work-type">{exp.type}</span>
                    <span className="period">{exp.period}</span>
                  </div>
                </div>
              </div>
              <div className="experience-description">
                <p>{exp.description}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
